오늘은 파이썬의 함수를 만들어서 사용하는 법(def), 자료형의 종류 등 그리고 ‘docstring’의 사용법과 ‘Decorator’에 대해 알아보았다. 12345678910111213141516# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 함수를 객체로 사용하는 방식# function as variabledef my_fun(): print(&quot;안녕&quot;)if __name__ == &quot;__main__&quot;: x = my_fun print(type(x)) print(x()) print_function = print print(print_function(&quot;파이썬 좋음&quot;)) &lt;결과 화면&gt; 12345678&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_1_basic.py&quot;&lt;class 'function'&gt;안녕None파이썬 좋음NoneProcess finished with exit code 0 1234567891011121314151617181920# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 다양한 함수를 리스트 안에 넣기# 딕셔너리에 추가하기def my_fun(): print(&quot;안녕&quot;)if __name__ == &quot;__main__&quot;: list_functions = [my_fun, open, print] list_functions[2](&quot;전 리스트에 있습니다.&quot;) dict_functions = { &quot;fun_1&quot; : my_fun(), &quot;fun_2&quot; : open, &quot;fun_3&quot;: print, } print(dict_functions[&quot;fun_3&quot;](&quot;전 딕셔너리에 있습니다.&quot;)) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_2_basic.py&quot;전 리스트에 있습니다.안녕전 딕셔너리에 있습니다.NoneProcess finished with exit code 0 123456789101112131415161718192021222324252627282930313233# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-def my_fun(): return 42# 함수를 arguments로 사용하기도 함def docstring_exist(func): &quot;&quot;&quot;입력된 함수 내 docstring이 있는지 확인하는 함수 Args: func (callable): A function Returns: bool &quot;&quot;&quot; return func.__doc__ is not None # True or False 값 반환def no_docstring(): return 10def yes_docstring(): &quot;&quot;&quot;value 값을 반환합니다. &quot;&quot;&quot; return 10if __name__ == &quot;__main__&quot;: x = my_fun print(my_fun()) print(&quot;-----&quot;) print(docstring_exist(no_docstring)) print(docstring_exist(yes_docstring)) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_3_basic.py&quot;42-----FalseTrueProcess finished with exit code 0 123456789101112# Defining a function inside another functiondef a(): x = [3, 6, 9] def b(y): print(y) for value in x: b(x)if __name__ == &quot;__main__&quot;: print(a()) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_4_basic.py&quot;[3, 6, 9][3, 6, 9][3, 6, 9]NoneProcess finished with exit code 0 12345678910111213# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Defining a function inside another functiondef a(x, y): if x &gt; 5 and x &lt; 8 and y &gt; 5 and y &lt; 8: print(x * y) else: print(&quot;다른 값을 입력하세요!&quot;) # raise ValueError(&quot;X is {}, Y is {}&quot;.format(x, y))if __name__ == &quot;__main__&quot;: print(a(5, 4)) &lt;결과 화면&gt; 12345&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_5_basic.py&quot;다른 값을 입력하세요!NoneProcess finished with exit code 0 123456789101112# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-def whatsInside(): def please_print_me(s): print(s) # return 1 return please_print_meif __name__ == &quot;__main__&quot;: new_func = whatsInside() print(new_func(&quot;Hope this prints print()&quot;)) &lt;결과 화면&gt; 12345&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_7_basic.py&quot;Hope this prints print()NoneProcess finished with exit code 0 12345678910111213141516171819202122232425262728293031323334353637383940# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# func 이름이 들어간 덧셈 뺄셈믈 추가해본다.# func 안에 func을 추가한다.def math_functions(func_name): if func_name == &quot;add&quot;: def add(a, b): return a + b return add elif func_name == &quot;subtract&quot;: def subtract(a, b): return a - b return subtract elif func_name == &quot;multiple&quot;: def multiple(a, b): return a * b return multiple elif func_name == &quot;divide&quot;: def divide(a, b): return a // b return divide else: print(&quot;그 외에는 잘 모르겠습니다.&quot;)if __name__ == &quot;__main__&quot;: x = 100 y = 2 add = math_functions(&quot;add&quot;) print(&quot;100 + 2 = {}&quot;.format(add(x, y))) subtract = math_functions(&quot;subtract&quot;) print(&quot;100 - 2 = {}&quot;.format(subtract(x, y))) subtract = math_functions(&quot;multiple&quot;) print(&quot;100 * 2 = {}&quot;.format(subtract(x, y))) divide = math_functions(&quot;divide&quot;) print(&quot;100 / 2 = {}&quot;.format(divide(x, y))) # 정수 출력 &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step06_8_basic.py&quot;100 + 2 = 102100 - 2 = 98100 * 2 = 200100 / 2 = 50Process finished with exit code 0 1234567891011121314# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Builtin &gt; Global &gt; NonLocal &gt; Localx = 100def a(): x = 42 print(x)if __name__ == &quot;__main__&quot;: print(a()) # 차이점 확인 print(x) # 차이점 확인 &lt;결과 화면&gt; 123456&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step07_1_basic.py&quot;42None100Process finished with exit code 0 1234567891011121314# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Builtin &gt; Global &gt; NonLocal &gt; Local# global 키워드에 배웁니다.x = 100def a(): global x x = 10 print(x)if __name__ == &quot;__main__&quot;: print(a()) print(x) &lt;결과 화면&gt; 123456&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step07_2_basic.py&quot;10None10Process finished with exit code 0 12345678910111213141516171819# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# NonLocal Keywordx = 1000def a(): x = 10 def b(): nonlocal x # 주석처리 할 것 x = 100 print(x) b() print(x)if __name__ == &quot;__main__&quot;: print(a()) print(x) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step07_3_basic.py&quot;100100None1000Process finished with exit code 0 12345678910111213141516171819202122232425262728# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# global x, nonlocal x, x등 자유롭게 활용하여 다음과 같이 출력하세요.# 단 반드시, global x 또는 nonlocal x 등은 입력되어야 함# 변수는 x만 사용합니다.# 100, 70, 30, 70 순서대로 출력 됨x = 100# 문제 낼 것def a(): x = 70def b(): global x x = 70def c(): x = 30 print(x)if __name__ == &quot;__main__&quot;: # result = [] for function in [a, b, c]: function() print(x) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step07_4_basic.py&quot;100703070Process finished with exit code 0 12345678910111213141516# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Closuresdef a(): a = 5 def b(): print(a) return bif __name__ == &quot;__main__&quot;: func = a() func() print(type(func.__closure__)) print(len(func.__closure__)) print(func.__closure__[0].cell_contents) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_1_basic.py&quot;5&lt;class 'tuple'&gt;15Process finished with exit code 0 123456789101112131415161718192021222324252627282930313233343536373839404142434445# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-x = 100def a(value): def b(): print(value) return bif __name__ == &quot;__main__&quot;: my_func = a(x) print(my_func()) del(x) # x = 100을 삭제한 것 print(my_func()) print(len(my_func.__closure__)) print(my_func.__closure__[0].cell_contents)&quot;&quot;&quot;개념정리: Nested Functions- 하나의 function 안에 또다른 function이 있는 것. # outer functiondef parent(): # nested function def child(): pass return child 개념정리: Definitions - Nonlocal Variables- Nonlocal Variables: Variables defined in the parent function that are used by the child functiondef parent(arg_1, arg_2) # child() 함수 관점에서는 value &amp; my_dict은 nonlocal variables value = 22 my_dict = {&quot;A&quot;: 100} def child() print(2 * value) print(my_dict[&quot;A&quot;]) print(arg_1 + arg_2) return child&quot;&quot;&quot; &lt;결과 화면&gt; 123456789&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_2_basic.py&quot;100None100None1100Process finished with exit code 0 1234567891011121314151617181920# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Closure: Nonlocal Variables은 반환되는 함수에 붙여서 나오게 됨def parent(arg_1, arg_2): nonlocal_value = 100 nonlocal_my_dict = {&quot;A&quot;: 0} def child(): print(2 * nonlocal_value) print(nonlocal_my_dict[&quot;A&quot;]) print(arg_1 + arg_2) return childif __name__ == &quot;__main__&quot;: new_function = parent(100, 200) print([cell.cell_contents for cell in new_function.__closure__]) # 리스트로 반환 for cell in new_function.__closure__: # 단일 객체로 반환 print(cell.cell_contents) &lt;결과 화면&gt; 12345678&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_3_basic.py&quot;[100, 200, {'A': 0}, 100]100200{'A': 0}100Process finished with exit code 0 123456789101112131415161718192021222324# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-def check_closure(arg1, arg2): def inside_func(): print(&quot;arg1 was {}&quot;.format(arg1)) print(&quot;arg1 was {}&quot;.format(arg2)) return inside_funcif __name__ == &quot;__main__&quot;: my_func = check_closure(10, 100) # Closure 에 결측치 있는지 확인 print(my_func.__closure__ is not None) # 2개의 변수가 존재하는지 확인 print(len(my_func.__closure__) == 2) # closure value 확인 closure_values = [ my_func.__closure__[i].cell_contents for i in range(2) ] print(closure_values == [2, 10]) &lt;결과 화면&gt; 123456&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_4_basic.py&quot;TrueTrueFalseProcess finished with exit code 0 12345678910111213141516171819# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-def print_msg(): print('print_msg 함수입니다. ')def new_func(func): def call_func(): func() return call_funcnew_func = new_func(print_msg)# 삭제del(print_msg)if __name__ == &quot;__main__&quot;: print(new_func()) &lt;결과 화면&gt; 12345&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_5_basic.py&quot;print_msg 함수입니다. NoneProcess finished with exit code 0 1234567891011121314151617# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 과제, 함수를 활용하여 제곱 곱셈 함수 만들기def multiple_a(a): def multiple_b(b): return a * b return multiple_bif __name__ == &quot;__main__&quot;: m1 = multiple_a(1) m2 = multiple_a(2) m3 = multiple_a(3) print(m1(3)) print(m1(5)) print(m1(7)) &lt;결과 화면&gt; 123456&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step08_6_basic.py&quot;357Process finished with exit code 0 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Decorator를 이해하기 위해서는 앞에서 계속 설명해왔던 4가지 개념을 이해해야 함&quot;&quot;&quot;1. 객체로서의 함수2. Nested 함수3. Nonlocal Variable4. Closures&quot;&quot;&quot;&quot;&quot;&quot;@two_argsdef add(a, b): return a + bif __name__ == &quot;__main__&quot;: multiply(1, 5)&quot;&quot;&quot;def add(a, b): return a + b&quot;&quot;&quot;def two_args(func): # 그저 함수 return func&quot;&quot;&quot;&quot;&quot;&quot;def two_args(func): # 새로운 함수 def wrapper(a, b): # 수정전의 함수 반환 return func(a, b) # 새로운 함수 반환 return wrapper&quot;&quot;&quot;def two_args(func): # 새로운 함수 def wrapper(a, b): # 수정전의 함수 반환 return func(a * 2, b * 2) # 새로운 함수 반환 return wrapperif __name__ == &quot;__main__&quot;: new_add = two_args(add) print(new_add(1, 2)) &lt;결과 화면&gt; 1234&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_1_basic.py&quot;6Process finished with exit code 0 12345678910111213141516# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 기존 문법def two_args(func): def wrapper(a, b): return func(a * 3, b * 3) return wrapperdef multiple(a, b): return a * bif __name__ == &quot;__main__&quot;: new_multiple = two_args(multiple) print(new_multiple(2, 3)) &lt;결과 화면&gt; 1234&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_2_basic.py&quot;54Process finished with exit code 0 12345678910111213141516# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Decorator 문법def two_args(func): def wrapper(a, b): return func(a * 3, b * 3) return wrapper@two_argsdef multiple(a, b): return a * bif __name__ == &quot;__main__&quot;: print(multiple(2, 3)) &lt;결과 화면&gt; 1234&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_3_basic.py&quot;54Process finished with exit code 0 123456789101112131415161718192021222324# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-import inspectdef print_args(func): sig = inspect.signature(func) # 객체는 콜러블 객체의 호출 서명과 반환 값 어노테이션을 나타냅니다. print(sig) def wrapper(*args, **kwargs): bound = sig.bind(*args, **kwargs).arguments # 반복문 돌리기 위해 딕셔너리 형태로 묶어줌 str_args = ', '.join(['{}={}'.format(k, v) for k, v in bound.items()]) print('{} was called with {}'.format(func.__name__, str_args)) return func(*args, **kwargs) return wrapper@print_argsdef my_function(a, b, c): print(a + b + c)if __name__ == &quot;__main__&quot;: # my_function = print_args(my_function) # 데코레이터 안할 시 print(my_function(1, 2, 3)) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_4_basic.py&quot;(a, b, c)my_function was called with a=1, b=2, c=36NoneProcess finished with exit code 0 아래의 코드는 시간이 얼마나 걸리는지 체크해 주는 함수를 직접 만든 것이다. 123456789101112131415161718192021222324252627# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 시간 측정 함수 만들기# time Decorator 만들기import timedef timer(func): &quot;&quot;&quot;함수 실행 시 얼마나 오래 걸리는지 확인&quot;&quot;&quot; def wrapper(*args, **kwargs): # 현재시간 time_start = time.time() # decorated 함수 불러오기 result = func(*args, **kwargs) time_total = time.time() - time_start print(&quot;{} took {}s&quot;.format(func.__name__, time_total)) return result return wrapper@timerdef check_time(num): time.sleep(num)if __name__ == &quot;__main__&quot;: check_time(3) &lt;결과 화면&gt; 1234&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_5_basic.py&quot;check_time took 3.0077176094055176sProcess finished with exit code 0 123456789101112131415161718192021# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# 데코레이터 함수 만들기def return_type(func): def wrapper(*args, **kwargs): result = func(*args, **kwargs) print('{}() returned type {}'.format(func.__name__, type(result))) return result return wrapper@return_typedef a(value): return valueif __name__ == &quot;__main__&quot;: print(a(123)) print(a([1, 2, 3])) print(a({&quot;a&quot;: 42})) &lt;결과 화면&gt; 123456789&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/Desktop/python_f/step09_6_basic.py&quot;a() returned type &lt;class 'int'&gt;123a() returned type &lt;class 'list'&gt;[1, 2, 3]a() returned type &lt;class 'dict'&gt;{'a': 42}Process finished with exit code 0 123456789101112131415161718192021222324# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# Counter# 특정 함수가 몇번 불러왔는지 확인하는 함수def counter(func): def wrapper(*args, **kwargs): wrapper.count += 1 return func(*args, **kwargs) wrapper.count = 0 return wrapper@counterdef a(): print(&quot;임의의 함수 호출&quot;)if __name__ == &quot;__main__&quot;: a() a() a() print(&quot;a() 함수는 현재 {} 번 호출됨&quot;.format(a.count)) &lt;결과 화면&gt; 1234567&quot;C:\Program Files\anaconda3\python.exe&quot; &quot;C:/Users/rudal/python_f/step09_7_basic.py&quot;임의의 함수 호출임의의 함수 호출임의의 함수 호출a() 함수는 현재 3 번 호출됨Process finished with exit code 0 123456789101112131415161718192021222324252627# /c/ProgramData/Anaconda3/python# -*- coding: utf-8 -*-# (2) 추가from functools import wraps# 메타데이터def print_hello(func): @wraps(func) def wrapper(*args, **kwargs): &quot;&quot;&quot;안녕을 출력하는 데커레이션 함수입니다.&quot;&quot;&quot; # (1) 추가 print('안녕') return func(*args, **kwargs) return wrapper# Decorate print_sum() with the add_hello() decorator@print_hellodef print_add(a, b): &quot;&quot;&quot;덧셈을 출력하는 함수입니다. &quot;&quot;&quot; print(a + b)if __name__ == &quot;__main__&quot;: print_add(10, 20) print_sum_docstring = print_add.__doc__ prin